// // This module designs a 4-bit down counter that decrements its value on the falling edge of the clock signal (clk). When the reset signal is asserted, the counter is reset to zero.
module top_module(
    input clk,
    input reset,
    output reg [3:0] counter
);always @(posedge clk) begin
    if (reset) begin
        counter <= 4'b0;
    end else begin
        counter <= counter + 1;
    end
end

endmodule
